Debounce delays invoking a function until a specified time has passed since its last call, useful for limiting how often expensive operations (like API calls on keystrokes) run.

```javascript
function debounce(fn, delay) {
  let timeoutId;
  return function (...args) {
    clearTimeout(timeoutId);
    timeoutId = setTimeout(() => fn.apply(this, args), delay);
  };
}

// Example usage:
const handleSearch = debounce((query) => {
  console.log('Searching for:', query);
}, 300);

handleSearch('h');
handleSearch('he');
handleSearch('hel');
handleSearch('hello');
// Only logs once, 300ms after the last call: "Searching for: hello"
```
